pragma solidity ^0.4.0;

contract Lotto {
    uint public constant blocksPerRound = 6800;

    uint public constant ticketPrice = 100000000000000000;

    uint public constant blockReward = 5000000000000000000;

    function getBlocksPerRound() constant returns (uint) {
        return blocksPerRound;
    }
    function getTicketPrice() constant returns (uint) {
        return ticketPrice;
    }

    struct Round {
        address[] buyers;
        uint pot;
        uint ticketsCount;
        mapping(uint => bool) isCashed;
        mapping(address => uint) ticketsCountByBuyer;
    }
    mapping(uint => Round) rounds;

    function getRoundIndex() constant returns (uint) {
        return block.number / blocksPerRound;
    }

    function getIsCashed(
        uint roundIndex,
        uint subpotIndex
    ) constant returns (bool) {
        return rounds[roundIndex].isCashed[subpotIndex];
    }

    function calculateWinner(
        uint roundIndex,
        uint subpotIndex
    ) constant returns (address) {
        var decisionBlockNumber = getDecisionBlockNumber(
            roundIndex,
            subpotIndex
        );

        if (decisionBlockNumber > block.number) return;

        var decisionBlockHash = getHashOfBlock(decisionBlockNumber);
        var winningTicketIndex = decisionBlockHash %
            rounds[roundIndex].ticketsCount;

        var ticketIndex = uint256(0);

        for (
            var buyerIndex = 0;
            buyerIndex < rounds[roundIndex].buyers.length;
            buyerIndex++
        ) {
            var buyer = rounds[roundIndex].buyers[buyerIndex];
            ticketIndex += rounds[roundIndex].ticketsCountByBuyer[buyer];

            if (ticketIndex > winningTicketIndex) {
                return buyer;
            }
        }
    }

    function getDecisionBlockNumber(
        uint roundIndex,
        uint subpotIndex
    ) constant returns (uint) {
        return ((roundIndex + 1) * blocksPerRound) + subpotIndex;
    }

    function getSubpotsCount(uint roundIndex) constant returns (uint) {
        var subpotsCount = rounds[roundIndex].pot / blockReward;

        if (rounds[roundIndex].pot % blockReward > 0) subpotsCount++;

        return subpotsCount;
    }

    function getSubpot(uint roundIndex) constant returns (uint) {
        return rounds[roundIndex].pot / getSubpotsCount(roundIndex);
    }

    function cash(uint roundIndex, uint subpotIndex) {
        var subpotsCount = getSubpotsCount(roundIndex);

        if (subpotIndex >= subpotsCount) return;

        var decisionBlockNumber = getDecisionBlockNumber(
            roundIndex,
            subpotIndex
        );

        if (decisionBlockNumber > block.number) return;

        if (rounds[roundIndex].isCashed[subpotIndex]) return;

        var winner = calculateWinner(roundIndex, subpotIndex);
        var subpot = getSubpot(roundIndex);

        winner.send(subpot);

        rounds[roundIndex].isCashed[subpotIndex] = true;
    }

    function getHashOfBlock(uint blockIndex) constant returns (uint) {
        return uint(block.blockhash(blockIndex));
    }

    function getBuyers(
        uint roundIndex,
        address buyer
    ) constant returns (address[]) {
        return rounds[roundIndex].buyers;
    }

    function getTicketsCountByBuyer(
        uint roundIndex,
        address buyer
    ) constant returns (uint) {
        return rounds[roundIndex].ticketsCountByBuyer[buyer];
    }

    function getPot(uint roundIndex) constant returns (uint) {
        return rounds[roundIndex].pot;
    }

    function() {
        var roundIndex = getRoundIndex();
        var value = msg.value - (msg.value % ticketPrice);

        if (value == 0) return;

        if (value < msg.value) {
            msg.sender.send(msg.value - value);
        }

        var ticketsCount = value / ticketPrice;
        rounds[roundIndex].ticketsCount += ticketsCount;

        if (rounds[roundIndex].ticketsCountByBuyer[msg.sender] == 0) {
            var buyersLength = rounds[roundIndex].buyers.length++;
            rounds[roundIndex].buyers[buyersLength] = msg.sender;
        }

        rounds[roundIndex].ticketsCountByBuyer[msg.sender] += ticketsCount;
        rounds[roundIndex].ticketsCount += ticketsCount;

        rounds[roundIndex].pot += value;
    }
}

Here are nine common vulnerabilities:

ID: Access Control
Description: Improper restriction of function access, allowing unauthorized users to execute critical functions.

ID: Arithmetic
Description: Missing or incorrect integer overflow/underflow checks, leading to unexpected values.

ID: Bad Randomness
Description: Use of predictable values for randomness, which attackers can manipulate.

ID: Denial Of Service
Description: Malicious actions that consume excessive gas or exploit fallback behavior to block contract functionality.

ID: Front Running
Description: Exploiting transaction order to manipulate outcomes before others.

ID: Reentrancy
Description: Recursive calls into the same contract before the initial function completes, leading to unexpected state changes.

ID: Short Addresses
Description: Failure to validate input lengths, allowing crafted shorter inputs to corrupt parameters.

ID: Time Manipulation
Description: Dependence on block timestamps that miners can influence.

ID: Unchecked Low Level Calls
Description: Calls to low-level functions like 'call()' without checking return values, which can silently fail.


Here is a complete example of the expected output format, followed by additional examples showing how individual vulnerabilities may be identified and explained:

- Example 1
Input:
```
function initContract() public {
	owner = msg.sender;
}
```
Output:
Access Control: Present
Explanation: The contract's initialization function sets the caller as the owner but is not part of the constructor. It lacks access restrictions and does not track whether it has already been called. As a result, any user can invoke the function and assign ownership to themselves, potentially leading to unauthorized access to privileged functionality.

Arithmetic: Absent
Explanation: The snippet does not contain arithmetic operations suggesting overflow or underflow issues.

Bad Randomness: Absent
Explanation: The snippet does not use any randomness source.

Denial Of Service: Absent
Explanation: The snippet does not show an external interaction or blocking pattern that would cause denial of service.

Front Running: Absent
Explanation: The snippet does not expose a transaction-order-dependent action or secret that could be exploited by observing pending transactions.

Reentrancy: Absent
Explanation: The snippet does not perform an external call that could allow reentrant execution.

Short Addresses: Absent
Explanation: The snippet does not process external address or calldata inputs in a way that suggests a short address issue.

Time Manipulation: Absent
Explanation: The snippet does not depend on block timestamps or time-related block properties.

Unchecked Low Level Calls: Absent
Explanation: The snippet does not use low-level calls such as call(), delegatecall(), or send().


